const fetchData = require("../utils/fetchData");

async function getEvents(apiKey) {
  const url = `https://api.jkt48connect.my.id/api/events?api_key=${apiKey}`;
  const response = await fetchData(url); // Mendapatkan data dari API
  return response; // Mengembalikan respons data langsung
}

async function getEventDetail(apiKey, eventId) {
  const url = `https://api.jkt48connect.my.id/api/events/${eventId}?api_key=${apiKey}`;
  const response = await fetchData(url); // Mendapatkan data dari API
  return response; // Mengembalikan respons data langsung
}

module.exports = { getEvents, getEventDetail };
